import{_ as t,o as n,c as i,ae as o}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Enable TikTok For Business","description":"","frontmatter":{"title":"Enable TikTok For Business","slug":"enable-tiktok-for-business"},"headers":[],"relativePath":"marketer-hub/enable-tiktok-for-business.md","filePath":"marketer-hub/enable-tiktok-for-business.md"}'),a={name:"marketer-hub/enable-tiktok-for-business.md"};function r(s,e,l,u,p,d){return n(),i("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>By connecting Branch and TikTok For Business, the following is enabled:</p><ul><li>App conversion data collected by the Branch SDK is sent to TikTok For Business for attribution through the self-attributing network (SAN) integration.</li><li>Read-only access to import click and impression data from TikTok For Business into your Branch account.</li><li>Deep link into in-app experiences (campaign specific)</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable TikTok For Business, you need to have completed the following:</p><ol><li><p>Created a Branch Dashboard.</p></li><li><p>Enabled Ads for your Branch account.</p><ul><li>Contact your Branch account manager or visit <a href="https://branch.io/pricing" target="_blank" rel="noreferrer">https://branch.io/pricing</a></li></ul></li><li><p>Implement the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p>Admin access to your TikTok For Business account.</p></li><li><p>Your App needs to be connected to your TikTok For Business account.</p></li></ol><h2 id="enable-tiktok-for-business" tabindex="-1">Enable TikTok For Business <a class="header-anchor" href="#enable-tiktok-for-business" aria-label="Permalink to &quot;Enable TikTok For Business&quot;">​</a></h2><h3 id="_1-connect-tiktok-for-business-in-branch" tabindex="-1">1. Connect TikTok For Business in Branch <a class="header-anchor" href="#_1-connect-tiktok-for-business-in-branch" aria-label="Permalink to &quot;1. Connect TikTok For Business in Branch&quot;">​</a></h3><p>In the Branch Dashboard under <strong>Ads</strong> → <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer"><strong>Partner Management</strong></a>, find/search for <strong>TikTok For Business SAN</strong>. If you&#39;re already logged into the Branch Dashboard, you can also click <a href="https://dashboard.branch.io/ads/partner-management/a_tiktok?tab=settings" target="_blank" rel="noreferrer">here</a> to go there directly.</p><p>Click the <strong>Log In With TikTok</strong> button and follow the prompts to authenticate your TikTok For Business account</p><p>Be sure to read and agree to the permissions requested by Branch in order to properly authenticate.</p><p><em>[Image: 1572]</em></p><h3 id="_2-input-your-tiktok-app-id" tabindex="-1">2. Input your TikTok App ID <a class="header-anchor" href="#_2-input-your-tiktok-app-id" aria-label="Permalink to &quot;2. Input your TikTok App ID&quot;">​</a></h3><p><em>This is a required field.</em> In your TikTok For Business <strong>Events Manager</strong>, generate your <strong>TikTok App ID</strong> (TTAID) for your app (iOS and/or Android). You can learn more about the TikTok App ID <a href="https://ads.tiktok.com/help/article?aid=10001060" target="_blank" rel="noreferrer">here</a>.</p><p>Once generated, copy/paste the respective TikTok App ID(s) into the TikTok For Business Ad Partner Settings. More than one TikTok App IDs can be added using a comma as a separator (no spaces).</p><p>Click the blue <strong>Save</strong> button to complete the authentication.</p><h3 id="_3-configure-events" tabindex="-1">3. Configure Events <a class="header-anchor" href="#_3-configure-events" aria-label="Permalink to &quot;3. Configure Events&quot;">​</a></h3><p>After authenticating your TikTok For Business account to Branch, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_tiktok?tab=event_config" target="_blank" rel="noreferrer"><strong>Events Config</strong></a> tab to configure your events.</p><p>It is important to add your event mappings here for Branch to properly send event metadata to TikTok For Business for attribution. You should see the events you are tracking with the Branch SDK here when you <strong>Add Event Mappings</strong>. Find the event you want to link and update the field with one of the predefined TikTok For Business (SAN) event names.<br> For more details on the TikTok For Business and Branch event and metadata mapping, see the specifications <a href="./tiktok-data-reporting.html">here</a>.</p><div class="info custom-block"><p class="custom-block-title">Additional Event Details</p><ul><li>If you plan to run TikTok SKAN Campaigns and are tracking Custom Events, make sure you map your Custom Event to TikTok&#39;s Standard Event.</li></ul></div><p>Click the blue <strong>Save</strong> button to set your event mappings.</p><h3 id="_4-configure-attribution-windows" tabindex="-1">4. Configure Attribution Windows <a class="header-anchor" href="#_4-configure-attribution-windows" aria-label="Permalink to &quot;4. Configure Attribution Windows&quot;">​</a></h3><p>After configuring your events, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_tiktok?tab=attribution_windows" target="_blank" rel="noreferrer"><strong>Attribution Windows</strong></a> tab to set windows by attribution type.</p><p>You have full freedom to choose your attribution windows; however, it may cause discrepancies between Branch and TikTok For Business when comparing reports.</p><p>Recommended Attribution Windows:</p><table tabindex="0"><thead><tr><th>Attribution Type</th><th>Window</th></tr></thead><tbody><tr><td>click to session start</td><td>7 days</td></tr><tr><td>click to install</td><td>7 days</td></tr><tr><td>click to conversion event</td><td>7 days</td></tr><tr><td>impression to session start</td><td>1 day</td></tr><tr><td>impression to install</td><td>1 day</td></tr><tr><td>impression to conversion event</td><td>1 day</td></tr></tbody></table><h3 id="_5-launch-tiktok-for-business-campaigns" tabindex="-1">5. Launch TikTok For Business Campaigns <a class="header-anchor" href="#_5-launch-tiktok-for-business-campaigns" aria-label="Permalink to &quot;5. Launch TikTok For Business Campaigns&quot;">​</a></h3><p>In TikTok For Business Ads Manager, you can now launch your campaigns, and the integration will take care of measuring performance.</p><p>Please visit the <a href="https://ads.tiktok.com/help/article/campaign-set-up?redirected=2" target="_blank" rel="noreferrer">TikTok For Business Help Center</a> for details on campaign setup.</p><h3 id="optional-use-branch-ad-link" tabindex="-1">[OPTIONAL] - Use Branch Ad Link <a class="header-anchor" href="#optional-use-branch-ad-link" aria-label="Permalink to &quot;[OPTIONAL] - Use Branch Ad Link&quot;">​</a></h3><p>You can use a <a href="./ad-links.html">Branch Ad Link</a> in your TikTok For Business campaigns for deep linking.</p><h4 id="using-your-tiktok-for-business-link-in-tiktok-ads" tabindex="-1">Using Your TikTok For Business Link in TikTok Ads <a class="header-anchor" href="#using-your-tiktok-for-business-link-in-tiktok-ads" aria-label="Permalink to &quot;Using Your TikTok For Business Link in TikTok Ads&quot;">​</a></h4><p>In your TikTok Ads Account:</p><ol><li><p>Click the Library tab and select Assets &gt; Event &gt; Manager App Event &gt; Create New App to create a new app or view previously added apps.</p></li><li><p>Provide your app&#39;s Download URL Settings. (Use your app&#39;s app store / play store address)</p></li><li><p>In the Tracking Settings section, select <strong>Branch</strong> as your Measurement Partner.</p></li><li><p>Place your TikTok For Business Link in the Click Tracking URL field and click <strong>Confirm</strong>.</p></li><li><p>Place your TikTok For Business impression link in the Default Impression Tracking URL field and click <strong>Confirm</strong>.</p></li></ol><h2 id="deep-linking-from-tiktok-for-business" tabindex="-1">Deep Linking from Tiktok For Business <a class="header-anchor" href="#deep-linking-from-tiktok-for-business" aria-label="Permalink to &quot;Deep Linking from Tiktok For Business&quot;">​</a></h2><p>Please consult with your app development team to set up deep linking for your TikTok For Business campaigns. TikTok For Business supports deep links using the following:</p><ul><li><p>Direct/Deferred Deep Linking</p><ul><li>Deep linking is supported through Branch Ad Links. View the <a href="./enable-tiktok-for-business.html#optional-use-branch-ad-link">optional step above</a> on using Branch Ad Links in TikTok For Business.</li></ul></li><li><p><a href="./android-app-links.html">Android App Links</a></p></li><li><p><a href="./ios-universal-links.html">iOS Universal Links</a></p></li></ul>',37)])])}const c=t(a,[["render",r]]);export{h as __pageData,c as default};
